+    fn prune_expired_revocations_removes_stale_entries() {
+        let cell = test_cell();
+        let mut cursor = FabricConsumerCursor::new(&cell).expect("cursor");
+        let window = SequenceWindow::new(50, 55).expect("window");
+        let relay = NodeId::new("relay-prune");
